1	'use server'
2	import { prisma } from '@/lib/prisma'
3	import { requireAdmin } from '@/lib/auth'
4	import { wordSaveSchema } from './schema'
5	import type { ActionResult } from '@/lib/errors'
6	
7	export async function createWord(input: unknown): Promise<ActionResult<{ id: number }>> {
8	  await requireAdmin()
9	  const parsed = wordSaveSchema.safeParse(input)
10	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
11	
12	  try {
13	    const word = await prisma.word.create({ data: parsed.data })
14	    return { success: true, data: { id: word.id } }
15	  } catch (err) {
16	    console.error('[createWord] prisma error', err)
17	    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
18	  }
19	}
20	
21	export async function updateWord(id: number, input: unknown): Promise<ActionResult> {
22	  await requireAdmin()
23	  const parsed = wordSaveSchema.safeParse(input)
24	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
25	
26	  try {
27	    await prisma.word.update({ where: { id }, data: parsed.data })
28	    return { success: true, data: undefined }
29	  } catch (err) {
30	    console.error('[updateWord] prisma error', err)
31	    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
32	  }
33	}
34	
35	export async function deleteWord(id: number): Promise<ActionResult> {
36	  await requireAdmin()
37	  try {
38	    await prisma.word.delete({ where: { id } })
39	    return { success: true, data: undefined }
40	  } catch (err) {
41	    console.error('[deleteWord] prisma error', err)
42	    return { success: false, error: '삭제 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
43	  }
44	}
